// CUDA kernel for 2D average pooling with NHWC layout
// Input and output are in channels_last format (NHWC)
__global__ void avgpool_kernel(
    const float* __restrict__ input,
    float* __restrict__ output,
    int batch_size,
    int channels,
    int input_H,
    int input_W,
    int kernel_size,
    int stride,
    int output_H,
    int output_W
) {
    // Each thread processes one output element
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total_elements = batch_size * output_H * output_W * channels;

    if (idx >= total_elements) return;

    // Decode indices for NHWC layout
    int c = idx % channels;
    int temp = idx / channels;
    int w_out = temp % output_W;
    temp = temp / output_W;
    int h_out = temp % output_H;
    int n = temp / output_H;

    // Starting position in input
    int h_in_start = h_out * stride;
    int w_in_start = w_out * stride;

    // Accumulate sum over the pooling window
    float sum = 0.0f;
    int count = 0;

    for (int kh = 0; kh < kernel_size; ++kh) {
        int h_in = h_in_start + kh;
        if (h_in >= input_H) break;

        for (int kw = 0; kw < kernel_size; ++kw) {
            int w_in = w_in_start + kw;
            if (w_in >= input_W) break;

            // NHWC layout: [n, h, w, c]
            int input_idx = ((n * input_H + h_in) * input_W + w_in) * channels + c;
            sum += input[input_idx];
            count++;
        }
    }

    // Compute average
    output[idx] = sum / float(count);
}

extern "C" {

void avgpool(
    float* input,
    float* output,
    int batch_size,
    int channels,
    int input_H,
    int kernel_size,
    int stride
) {
    // Assume square input (input_W == input_H) and square kernel
    int input_W = input_H;
    int output_H = (input_H - kernel_size) / stride + 1;
    int output_W = (input_W - kernel_size) / stride + 1;

    int total_elements = batch_size * output_H * output_W * channels;

    // Configure kernel launch
    int threads_per_block = 256;
    int num_blocks = (total_elements + threads_per_block - 1) / threads_per_block;

    avgpool_kernel<<<num_blocks, threads_per_block>>>(
        input,
        output,
        batch_size,
        channels,
        input_H,
        input_W,
        kernel_size,
        stride,
        output_H,
        output_W
    );

    // Optional: check for errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        printf("CUDA kernel launch error: %s\n", cudaGetErrorString(err));
    }
}

} // extern "C"
