"""Backend abstraction layer for optest framework."""

from abc import ABC, abstractmethod
from typing import List, Any, Callable
import torch


class Backend(ABC):
    """Abstract base class for all backends."""

    @property
    @abstractmethod
    def name(self) -> str:
        """Backend name."""
        pass

    @abstractmethod
    def load_kernel(self, testcase_dir: str, argtypes: List[Any]) -> Callable:
        """Load kernel function."""
        pass

    @abstractmethod
    def prepare_inputs(self, inputs: List[Any]) -> List[Any]:
        """Prepare inputs (e.g., convert to pointers)."""
        pass

    @abstractmethod
    def execute(self, kernel: Callable, inputs: List[Any]) -> Any:
        """Execute the kernel."""
        pass


class TorchBackend(Backend):
    """PyTorch backend (reference implementation)."""

    @property
    def name(self) -> str:
        return "PyTorch"

    def load_kernel(self, testcase_dir: str, argtypes: List[Any]) -> Callable:
        raise NotImplementedError("PyTorch uses function directly, not compiled kernel")

    def prepare_inputs(self, inputs: List[Any]) -> List[Any]:
        return inputs  # No conversion needed

    def execute(self, kernel: Callable, inputs: List[Any]) -> Any:
        return kernel(*inputs)


class CUDABackend(Backend):
    """CUDA backend."""

    def __init__(self, arch: str = None):
        # Auto-detect GPU architecture if not specified
        if arch is None:
            try:
                import torch

                major, minor = torch.cuda.get_device_capability()
                self._arch = f"sm_{major}{minor}"
            except Exception:
                self._arch = "sm_80"  # Default fallback
        else:
            self._arch = arch

    @property
    def name(self) -> str:
        return "CUDA"

    def load_kernel(self, testcase_dir: str, argtypes: List[Any]) -> Callable:
        from optest.execution.compiler import compile_kernel

        lib_path = compile_kernel(testcase_dir, backend="cuda", arch=self._arch)
        import ctypes

        lib = ctypes.CDLL(lib_path)
        lib.cuda_kernel.argtypes = argtypes
        return lib.cuda_kernel

    def prepare_inputs(self, inputs: List[Any]) -> List[Any]:
        return [t.data_ptr() if isinstance(t, torch.Tensor) else t for t in inputs]

    def execute(self, kernel: Callable, inputs: List[Any]) -> Any:
        kernel(*inputs)
        torch.cuda.synchronize()  # Wait for CUDA kernel to complete
        return None  # Output tensors are already in inputs


class TritonBackend(Backend):
    """Triton backend."""

    @property
    def name(self) -> str:
        return "Triton"

    def load_kernel(self, testcase_dir: str, argtypes: List[Any]) -> Callable:
        import importlib.util

